const post = $input.first().json;
const data = $json;

// Normalize metrics from different platform API responses
let metrics = {
  post_id: post.id,
  platform: post.platform,
  views: 0,
  likes: 0,
  comments: 0,
  shares: 0,
  saves: 0,
  click_through: 0,
  watch_time_avg_seconds: 0,
};

if (post.platform === 'tiktok' && data.data?.videos?.[0]) {
  const v = data.data.videos[0];
  metrics.views = v.view_count || 0;
  metrics.likes = v.like_count || 0;
  metrics.comments = v.comment_count || 0;
  metrics.shares = v.share_count || 0;
}

if (post.platform === 'instagram' && data.data) {
  for (const insight of data.data) {
    if (insight.name === 'plays') metrics.views = insight.values?.[0]?.value || 0;
    if (insight.name === 'likes') metrics.likes = insight.values?.[0]?.value || 0;
    if (insight.name === 'comments') metrics.comments = insight.values?.[0]?.value || 0;
    if (insight.name === 'shares') metrics.shares = insight.values?.[0]?.value || 0;
    if (insight.name === 'saved') metrics.saves = insight.values?.[0]?.value || 0;
    if (insight.name === 'reach') metrics.click_through = insight.values?.[0]?.value || 0;
  }
}

if (post.platform === 'youtube' && data.items?.[0]?.statistics) {
  const s = data.items[0].statistics;
  metrics.views = parseInt(s.viewCount || '0', 10);
  metrics.likes = parseInt(s.likeCount || '0', 10);
  metrics.comments = parseInt(s.commentCount || '0', 10);
}

if (post.platform === 'facebook' && data.data) {
  for (const insight of data.data) {
    if (insight.name === 'post_video_views') metrics.views = insight.values?.[0]?.value || 0;
    if (insight.name === 'post_video_avg_time_watched') metrics.watch_time_avg_seconds = insight.values?.[0]?.value || 0;
  }
}

// Compute engagement rate
metrics.engagement_rate = metrics.views > 0
  ? ((metrics.likes + metrics.comments + metrics.shares + metrics.saves) / metrics.views * 100).toFixed(2)
  : 0;

return [{ json: { ...metrics, topic_id: post.topic_id } }];

const items = $input.all().map(i => i.json);

// Group by topic_id
const byTopic = {};
for (const item of items) {
  if (!item.topic_id) continue;
  if (!byTopic[item.topic_id]) {
    byTopic[item.topic_id] = { views: [], engagement: [] };
  }
  byTopic[item.topic_id].views.push(item.views || 0);
  byTopic[item.topic_id].engagement.push(parseFloat(item.engagement_rate) || 0);
}

// Compute averages and determine weight
const results = [];
for (const [topicId, data] of Object.entries(byTopic)) {
  const avgViews = Math.round(data.views.reduce((a, b) => a + b, 0) / data.views.length);
  const avgEngagement = (data.engagement.reduce((a, b) => a + b, 0) / data.engagement.length).toFixed(2);

  // Weight logic: top performers get 2x, average stays 1x, underperformers get 0.5x
  let weight = 1.0;
  if (avgEngagement > 5.0 || avgViews > 10000) weight = 2.0;  // Winner
  if (avgEngagement > 3.0 || avgViews > 5000) weight = 1.5;   // Good
  if (avgEngagement < 1.0 && avgViews < 500) weight = 0.5;    // Underperformer

  results.push({
    json: {
      topic_id: topicId,
      avg_views: avgViews,
      avg_engagement: parseFloat(avgEngagement),
      new_weight: weight,
    }
  });
}

return results;

const today = new Date();
if (today.getDay() !== 0) {
  // Not Sunday — skip weekly report
  return [];
}

const items = $input.all().map(i => i.json);

const totalViews = items.reduce((s, i) => s + (i.views || 0), 0);
const totalLikes = items.reduce((s, i) => s + (i.likes || 0), 0);
const totalComments = items.reduce((s, i) => s + (i.comments || 0), 0);
const totalShares = items.reduce((s, i) => s + (i.shares || 0), 0);
const avgEngagement = items.length > 0
  ? (items.reduce((s, i) => s + parseFloat(i.engagement_rate || 0), 0) / items.length).toFixed(2)
  : 0;

// Find top performing post
const topPost = items.sort((a, b) => (b.views || 0) - (a.views || 0))[0];

const report = {
  week_ending: today.toISOString().split('T')[0],
  total_posts: items.length,
  total_views: totalViews,
  total_likes: totalLikes,
  total_comments: totalComments,
  total_shares: totalShares,
  avg_engagement_rate: avgEngagement,
  top_post_platform: topPost?.platform || 'N/A',
  top_post_views: topPost?.views || 0,
  summary: `Week ending ${today.toISOString().split('T')[0]}:\n` +
    `Posts: ${items.length} | Views: ${totalViews.toLocaleString()} | ` +
    `Likes: ${totalLikes.toLocaleString()} | Comments: ${totalComments.toLocaleString()} | ` +
    `Shares: ${totalShares.toLocaleString()}\n` +
    `Avg engagement: ${avgEngagement}%\n` +
    `Top post: ${topPost?.platform || 'N/A'} with ${(topPost?.views || 0).toLocaleString()} views`
};

return [{ json: report }];
